/**
 * Email Processing Orchestrator Tests (T040)
 *
 * TDD Approach: Test batch processing pipelines, error handling, batch coordination, and performance metrics
 *
 * Test Categories:
 * 1. Batch processing with successful emails
 * 2. Error handling for individual email failures
 * 3. Performance metrics tracking
 * 4. Batch coordination with mixed success/failure
 * 5. Configuration validation
 */

import {
  EmailProcessor,
  GmailClient,
  ClassificationOrchestrator,
  PersistenceService,
} from '../../src/orchestrator/email-processor';
import { EmailMessage } from '../../../classification-engine/src/types/email-message';
import { ClassificationResult } from '../../../classification-engine/src/types/classification-result';
import { ProcessingConfig } from '../../../classification-engine/src/types/category-configuration';
import { validMinimalProcessingConfig } from '../../../classification-engine/tests/fixtures/configs';

// Mock dependencies (Gmail client, classification orchestrator, persistence)
interface MockGmailClient {
  fetchEmails: jest.Mock;
  fetchEmailById: jest.Mock;
}

interface MockClassificationOrchestrator {
  classifyBatch: jest.Mock;
  classify: jest.Mock;
}

interface MockPersistence {
  saveClassificationBatch: jest.Mock;
  saveClassificationResult: jest.Mock;
}

describe('EmailProcessor', () => {
  let mockGmailClient: MockGmailClient;
  let mockClassificationOrchestrator: MockClassificationOrchestrator;
  let mockPersistence: MockPersistence;
  let testConfig: ProcessingConfig;

  beforeEach(() => {
    // Setup mock dependencies
    mockGmailClient = {
      fetchEmails: jest.fn(),
      fetchEmailById: jest.fn(),
    };

    mockClassificationOrchestrator = {
      classifyBatch: jest.fn(),
      classify: jest.fn(),
    };

    mockPersistence = {
      saveClassificationBatch: jest.fn(),
      saveClassificationResult: jest.fn(),
    };

    // Use valid minimal configuration from fixtures
    testConfig = validMinimalProcessingConfig;
  });

  describe('Constructor and Initialization', () => {
    test('should initialize with valid dependencies and config', () => {
      expect(() => {
        new EmailProcessor(
          mockGmailClient as unknown as GmailClient,
          mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
          mockPersistence as unknown as PersistenceService,
          testConfig
        );
      }).not.toThrow();
    });

    test('should throw error if config is invalid', () => {
      expect(() => {
        new EmailProcessor(
          mockGmailClient as unknown as GmailClient,
          mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
          mockPersistence as unknown as PersistenceService,
          {} as ProcessingConfig
        );
      }).toThrow('Invalid configuration');
    });
  });

  describe('Batch Processing', () => {
    test('should process batch of emails successfully', async () => {
      const mockEmails: EmailMessage[] = [
        createMockEmail('msg1', 'Test Subject 1'),
        createMockEmail('msg2', 'Test Subject 2'),
        createMockEmail('msg3', 'Test Subject 3'),
      ];

      const mockClassificationResults: ClassificationResult[] = [
        createMockClassificationResult('msg1', 0.85),
        createMockClassificationResult('msg2', 0.9),
        createMockClassificationResult('msg3', 0.75),
      ];

      mockGmailClient.fetchEmails.mockResolvedValue(mockEmails);
      mockClassificationOrchestrator.classifyBatch.mockResolvedValue(mockClassificationResults);
      mockPersistence.saveClassificationBatch.mockResolvedValue(undefined);

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      const result = await processor.processBatch({ maxEmails: 10 });

      expect(result.totalProcessed).toBe(3);
      expect(result.successCount).toBe(3);
      expect(result.errorCount).toBe(0);
      expect(result.processingDurationMs).toBeGreaterThanOrEqual(0);
      expect(mockGmailClient.fetchEmails).toHaveBeenCalledTimes(1);
      expect(mockClassificationOrchestrator.classifyBatch).toHaveBeenCalledWith(mockEmails);
      expect(mockPersistence.saveClassificationBatch).toHaveBeenCalledTimes(1);
    });

    test('should handle individual email classification errors in batch', async () => {
      const mockEmails: EmailMessage[] = [
        createMockEmail('msg1', 'Test Subject 1'),
        createMockEmail('msg2', 'Test Subject 2'),
        createMockEmail('msg3', 'Test Subject 3'),
      ];

      // Second email fails classification
      const mockClassificationResults = [
        createMockClassificationResult('msg1', 0.85),
        { error: new Error('Classification failed'), emailId: 'msg2', processingDurationMs: 100 },
        createMockClassificationResult('msg3', 0.75),
      ];

      mockGmailClient.fetchEmails.mockResolvedValue(mockEmails);
      mockClassificationOrchestrator.classifyBatch.mockResolvedValue(mockClassificationResults);
      mockPersistence.saveClassificationBatch.mockResolvedValue(undefined);

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      const result = await processor.processBatch({ maxEmails: 10 });

      expect(result.totalProcessed).toBe(3);
      expect(result.successCount).toBe(2);
      expect(result.errorCount).toBe(1);
      expect(result.errors).toHaveLength(1);
      expect(result.errors[0].emailId).toBe('msg2');
      expect(result.errors[0].error.message).toBe('Classification failed');
    });

    test('should handle persistence errors gracefully', async () => {
      const mockEmails: EmailMessage[] = [createMockEmail('msg1', 'Test Subject 1')];
      const mockClassificationResults: ClassificationResult[] = [createMockClassificationResult('msg1', 0.85)];

      mockGmailClient.fetchEmails.mockResolvedValue(mockEmails);
      mockClassificationOrchestrator.classifyBatch.mockResolvedValue(mockClassificationResults);
      mockPersistence.saveClassificationBatch.mockRejectedValue(new Error('Database connection failed'));

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      await expect(processor.processBatch({ maxEmails: 10 })).rejects.toThrow('Database connection failed');
    });

    test('should handle empty email list', async () => {
      mockGmailClient.fetchEmails.mockResolvedValue([]);

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      const result = await processor.processBatch({ maxEmails: 10 });

      expect(result.totalProcessed).toBe(0);
      expect(result.successCount).toBe(0);
      expect(result.errorCount).toBe(0);
      expect(mockClassificationOrchestrator.classifyBatch).not.toHaveBeenCalled();
      expect(mockPersistence.saveClassificationBatch).not.toHaveBeenCalled();
    });
  });

  describe('Single Email Processing', () => {
    test('should process single email successfully', async () => {
      const mockEmail = createMockEmail('msg1', 'Test Subject');
      const mockClassificationResult = createMockClassificationResult('msg1', 0.85);

      mockGmailClient.fetchEmailById.mockResolvedValue(mockEmail);
      mockClassificationOrchestrator.classify.mockResolvedValue(mockClassificationResult);
      mockPersistence.saveClassificationResult.mockResolvedValue(undefined);

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      const result = await processor.processSingle('msg1');

      expect(result.success).toBe(true);
      expect(result.emailId).toBe('msg1');
      expect(result.classificationResult).toEqual(mockClassificationResult);
      expect(mockGmailClient.fetchEmailById).toHaveBeenCalledWith('msg1');
      expect(mockClassificationOrchestrator.classify).toHaveBeenCalledWith(mockEmail);
      expect(mockPersistence.saveClassificationResult).toHaveBeenCalledWith('msg1', mockClassificationResult);
    });

    test('should handle classification error for single email', async () => {
      const mockEmail = createMockEmail('msg1', 'Test Subject');

      mockGmailClient.fetchEmailById.mockResolvedValue(mockEmail);
      mockClassificationOrchestrator.classify.mockRejectedValue(new Error('Classification failed'));

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      const result = await processor.processSingle('msg1');

      expect(result.success).toBe(false);
      expect(result.emailId).toBe('msg1');
      expect(result.error).toBeDefined();
      expect(result.error?.message).toBe('Classification failed');
      expect(mockPersistence.saveClassificationResult).not.toHaveBeenCalled();
    });

    test('should handle email not found error', async () => {
      mockGmailClient.fetchEmailById.mockRejectedValue(new Error('Email not found'));

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      const result = await processor.processSingle('msg1');

      expect(result.success).toBe(false);
      expect(result.emailId).toBe('msg1');
      expect(result.error?.message).toBe('Email not found');
    });
  });

  describe('Performance Metrics', () => {
    test('should track processing duration accurately', async () => {
      const mockEmails: EmailMessage[] = [
        createMockEmail('msg1', 'Test Subject 1'),
        createMockEmail('msg2', 'Test Subject 2'),
      ];

      const mockClassificationResults: ClassificationResult[] = [
        createMockClassificationResult('msg1', 0.85),
        createMockClassificationResult('msg2', 0.9),
      ];

      mockGmailClient.fetchEmails.mockResolvedValue(mockEmails);
      mockClassificationOrchestrator.classifyBatch.mockResolvedValue(mockClassificationResults);
      mockPersistence.saveClassificationBatch.mockResolvedValue(undefined);

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      const result = await processor.processBatch({ maxEmails: 10 });

      expect(result.processingDurationMs).toBeGreaterThanOrEqual(0);
      expect(result.averageEmailDurationMs).toBeGreaterThanOrEqual(0);
      expect(result.averageEmailDurationMs).toBe(result.processingDurationMs / 2);
    });

    test('should include performance metrics in result', async () => {
      const mockEmails: EmailMessage[] = [createMockEmail('msg1', 'Test Subject 1')];
      const mockClassificationResults: ClassificationResult[] = [createMockClassificationResult('msg1', 0.85)];

      mockGmailClient.fetchEmails.mockResolvedValue(mockEmails);
      mockClassificationOrchestrator.classifyBatch.mockResolvedValue(mockClassificationResults);
      mockPersistence.saveClassificationBatch.mockResolvedValue(undefined);

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      const result = await processor.processBatch({ maxEmails: 10 });

      expect(result).toHaveProperty('processingDurationMs');
      expect(result).toHaveProperty('averageEmailDurationMs');
      expect(result).toHaveProperty('totalProcessed');
      expect(result).toHaveProperty('successCount');
      expect(result).toHaveProperty('errorCount');
    });
  });

  describe('Batch Options', () => {
    test('should respect maxEmails limit', async () => {
      const mockEmails: EmailMessage[] = Array.from({ length: 5 }, (_, i) =>
        createMockEmail(`msg${i + 1}`, `Subject ${i + 1}`)
      );

      const mockClassificationResults: ClassificationResult[] = mockEmails.map((email) =>
        createMockClassificationResult(email.id, 0.85)
      );

      mockGmailClient.fetchEmails.mockResolvedValue(mockEmails);
      mockClassificationOrchestrator.classifyBatch.mockResolvedValue(mockClassificationResults);
      mockPersistence.saveClassificationBatch.mockResolvedValue(undefined);

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      await processor.processBatch({ maxEmails: 3 });

      expect(mockGmailClient.fetchEmails).toHaveBeenCalledWith(expect.objectContaining({ maxEmails: 3 }));
    });

    test('should handle date range filters', async () => {
      const mockEmails: EmailMessage[] = [createMockEmail('msg1', 'Test Subject')];
      const mockClassificationResults: ClassificationResult[] = [createMockClassificationResult('msg1', 0.85)];

      mockGmailClient.fetchEmails.mockResolvedValue(mockEmails);
      mockClassificationOrchestrator.classifyBatch.mockResolvedValue(mockClassificationResults);
      mockPersistence.saveClassificationBatch.mockResolvedValue(undefined);

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      const startDate = new Date('2025-01-01');
      const endDate = new Date('2025-01-31');

      await processor.processBatch({ startDate, endDate, maxEmails: 10 });

      expect(mockGmailClient.fetchEmails).toHaveBeenCalledWith(expect.objectContaining({ startDate, endDate }));
    });
  });
});

// Helper functions for creating mock data
function createMockEmail(id: string, subject: string): EmailMessage {
  return {
    id,
    threadId: `thread-${id}`,
    gmailLabels: ['INBOX'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: subject },
        { name: 'From', value: 'sender@example.com' },
        { name: 'To', value: 'recipient@example.com' },
        { name: 'Date', value: new Date().toUTCString() },
      ],
      body: {
        data: Buffer.from('Test email body').toString('base64'),
      },
    },
    subject,
    from: {
      email: 'sender@example.com',
      name: 'Test Sender',
      raw: 'Test Sender <sender@example.com>',
    },
    to: [
      {
        email: 'recipient@example.com',
        name: 'Test Recipient',
        raw: 'Test Recipient <recipient@example.com>',
      },
    ],
    date: new Date(),
    bodyPlain: 'Test email body',
    isProcessed: false,
    processingPriority: 50,
  };
}

function createMockClassificationResult(emailId: string, confidence: number): ClassificationResult {
  return {
    selectedLabels: [
      {
        category: 'TEST_CATEGORY',
        subtype: 'test_subtype',
        confidence,
        score: confidence,
        isPrimary: true,
        labelOrder: 1,
        selectionRationale: 'Test rationale',
      },
    ],
    candidateScores: {
      TEST_CATEGORY: {
        score: confidence,
        confidence,
        decision: 'positive',
      },
    },
    selectionSummary: {
      totalLabels: 1,
      primaryCategory: 'TEST_CATEGORY',
      confidenceRange: [confidence, confidence],
      selectionMethod: 'multi_label',
      needsAi: false,
